function filterArticles(cat, btn) {
  document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  document.querySelectorAll('.article-card').forEach(card => {
    if (cat === 'all' || card.dataset.cat === cat) {
      card.style.display = '';
    } else {
      card.style.display = 'none';
    }
  });
  // Featured card always loses its grid-column when filtered
  const featured = document.querySelector('.article-card.featured');
  if (featured) {
    featured.style.gridColumn = (cat === 'all' || featured.dataset.cat === cat) ? '' : '';
  }
}



function toggleArticle(id) {
  var el  = document.getElementById(id + '-full');
  var btn = document.getElementById(id + '-btn');
  if (!el || !btn) return;
  var isHidden = el.style.display === 'none' || el.style.display === '';
  el.style.display = isHidden ? 'block' : 'none';
  if (currentLang === 'hr') {
    btn.textContent = isHidden ? 'Manje' : 'Pročitajte cijeli članak';
  } else {
    btn.textContent = isHidden ? 'Read Less' : 'Read Full Article';
  }
}



function toggleProfile(name) {
  const full = document.getElementById(name + '-full');
  const btn  = document.getElementById(name + '-btn');
  const isHidden = full.style.display === 'none';
  full.style.display = isHidden ? 'block' : 'none';
  if (currentLang === 'hr') {
    btn.textContent = isHidden ? 'Skupi profil ↑' : 'Proširi profil ↓';
  } else {
    btn.textContent = isHidden ? 'Collapse Profile ↑' : 'Expand Profile ↓';
  }
}



