TRANSLATIONS_HR['t-people-tag'] = 'Tim';
TRANSLATIONS_HR['sab-bio-short'] = 'Sabrina Buljubašić viša je sportska rukovoditeljica, međunarodna sportska odvjetnica i bivša profesionalna nogometašica. Njezino iskustvo obuhvaća vodstvo kluba, strateški razvoj, upravljanje i visoke razine football operacija, dajući Mentoriji rijetku kombinaciju rukovoditeljske prosudbe i industrijske vjerodostojnosti iz prve ruke.';
TRANSLATIONS_HR['sab-bio-full'] = 'Uspješna liderica prepoznata po rušenju barijera u globalnom footballu, Sabrina je bila prva žena imenovana izvršnom direktoricom muškog nogometnog kluba u Bosni i Hercegovini. Vodila je FK Sarajevo u povijesnu eru — osvajajući četiri značajna trofeja, uključujući prvi double naslov kluba i uzastopna ligaška prvenstava.<br><br>Dobitnica nagrade Leaders 40 Under 40, osnovala je Dynami Sports Group i postala prva osoba iz Bosne koja je položila FIFA agentski ispit. Zatim je vodila HNK Šibenik do promocije u Premijer ligu u svojoj prvoj godini u klubu. Sada obavlja dužnost generalne menadžerice u Hess Sports Group — londonskoj investicijskoj grupi koja razvija ženski sport globalno.';
TRANSLATIONS_HR['sab-highlight'] = '"Osnivačica Dynami Sports Group · Međunarodna sportska odvjetnica · Sportska rukovoditeljica · Bivša profesionalna nogometašica"';
TRANSLATIONS_HR['sab-badge1'] = '4× osvajačica trofeja — FK Sarajevo';
TRANSLATIONS_HR['sab-badge2'] = 'Prva žena izvršna direktorica — muški klub, BiH';
TRANSLATIONS_HR['sab-badge3'] = 'FIFA agent — prvi iz Bosne';
TRANSLATIONS_HR['sab-badge4'] = 'HNK Šibenik — promocija u Premijer ligu';
TRANSLATIONS_HR['sab-badge5'] = 'Nagrada Leaders 40 Under 40';
TRANSLATIONS_HR['sab-badge6'] = 'Hess Sports Group — generalna menadžerica';
TRANSLATIONS_HR['jas-bio-short'] = 'Jasmila Hodžić stručnjakinja je za sportsko pravo i viša nogometna rukovoditeljica s dubokim iskustvom u pravnom savjetovanju, upravljanju, regulatornim pitanjima i institucionalnom vodstvu. Njezin rad nalazi se na sjecištu nogometne administracije, usklađenosti, upravljanja dionicima i dugoročnog strateškog razvoja.';
TRANSLATIONS_HR['jas-bio-full'] = 'Obavlja dužnost generalne tajnice i glavne pravne savjetnice FK Sarajevo, gdje nadzire regulatornu usklađenost, međunarodne odnose i ključne operativne procese.<br><br>Posjeduje LL.M. sa Central European University i magistarski stupanj iz sportskog marketinga i pravnih vještina sa ISDE Law &amp; Business School, završen u partnerstvu s FC Barcelona. Dodatno je ojačala svoj rukovoditeljski profil kroz programe na Harvard Business School, EFC Club Management Programme i prestižnom EFC Women on Board Program.<br><br>Jasmila je aktivno uključena u europsko nogometno upravljanje kroz European Football Clubs, doprinoseći Pravnoj i regulatornoj radnoj skupini te sudjelujući u razvoju ključnih regulatornih okvira koji oblikuju moderni football. S dubokim znanjem iz ugovornog prava, rješavanja sporova i sportskog upravljanja, donosi perspektivu usmjerenu prema budućnosti za nogometne organizacije u jugoistočnoj Europi i na međunarodnoj sceni.';
TRANSLATIONS_HR['jas-highlight'] = '"Stručnjakinja za sportsko pravo · Generalna tajnica i CLO, FK Sarajevo · Članica radne skupine ECA · Stručnjakinja za upravljanje u footballu"';
TRANSLATIONS_HR['jas-badge1'] = 'Glavna pravna savjetnica — FK Sarajevo';
TRANSLATIONS_HR['jas-badge2'] = 'Generalna tajnica — FK Sarajevo';
TRANSLATIONS_HR['jas-badge3'] = 'LL.M. — Central European University';
TRANSLATIONS_HR['jas-badge4'] = 'MSc Sportsko pravo — ISDE × FC Barcelona';
TRANSLATIONS_HR['jas-badge5'] = 'Harvard Business School';
TRANSLATIONS_HR['jas-badge6'] = 'ECA Pravna i regulatorna radna skupina';
TRANSLATIONS_HR['t-people-h2'] = 'Ljudi<br>iza Mentorije';
TRANSLATIONS_HR['t-people-sub'] = 'Tim vodstva s iskustvom u elitnom footballu, pravnom savjetovanju, upravljanju, investicijskom dijalogu i institucionalnoj edukaciji.';
TRANSLATIONS_HR['t-sabrina-role'] = 'Suosnivačica';
TRANSLATIONS_HR['t-jasmila-role'] = 'Suosnivačica';
TRANSLATIONS_HR['t-articles-tag'] = 'Uvidi i vijesti';
TRANSLATIONS_HR['ptb-meta'] = 'Mentoria Uvidi &nbsp;·&nbsp; Edukacija';
TRANSLATIONS_HR['ptb-title'] = 'S terena u upravljački odbor: priprema sportaša za život nakon sporta';
TRANSLATIONS_HR['ptb-excerpt'] = 'Sportaši se umirovljuju mladi — ali njihove najbolje vještine upravo su ono što trebaju upravni odbori. Mentoria premošćuje jaz između terena i C-suite razine.';
TRANSLATIONS_HR['ptb-full-text'] = 'Prelazak iz profesionalnog sporta na drugu karijeru jedna je od najzahtjevnijih tranzicija koje osoba može napraviti. Kvalitete koje čine prvaka — otpornost, disciplina i strateško razmišljanje — upravo su ono što moderni upravni odbori žele zaposliti. U Mentoriji se usredotočujemo na tri ključna stupa: strateško vodstvo, financijsku pismenost i poslovnu mehaniku — pretvarajući bivše igrače u buduće rukovoditelje.<br><br><strong>Identitetska kriza: više od igre</strong><br>Za mnoge sportaše, kraj sportske karijere doživljava se kao gubitak identiteta. Naša misija je pružiti most koji pretvara sirovi atletski instinkt u rafiniranu korporativnu strategiju.<br><br><strong>Prenosivi priručnik</strong><br>Sportaši posjeduju specijalizirani skup alata koji većina MBA studenata provede godine pokušavajući simulirati. Elitna otpornost, petlja povratnih informacija i održani fokus izravno se prevode na poslovni uspjeh.<br><br><strong>Studije slučaja: pobjedništvo u drugom poluvremenu</strong><br>Od strateškog venture kapitaliste do operativnog COO-a i arhitektice marke — bivši sportaši koji su prošli Mentorija programe danas vode tvrtke i pokreu fondove.<br><br><strong>Redefiniranje umirovljenja</strong><br>Kada se sportaš umirovljuje s 30 ili 35 godina, ima 40 godina profesionalnog života ispred sebe. To nije kraj — to je drugo poluvrijeme.';
TRANSLATIONS_HR['wob-meta'] = 'Mentoria Uvidi &nbsp;·&nbsp; Upravljanje';
TRANSLATIONS_HR['wob-title'] = 'Suočavanje s jazom u upravljanju: zašto su žene u nogometnim odborima neophodne';
TRANSLATIONS_HR['wob-excerpt'] = 'Žene drže manje od 25% mjesta u odborima u sportu. Ovo nije samo pitanje ravnopravnosti — to je upravljačka kriza sa stvarnim posljedicama za budućnost footballa.';
TRANSLATIONS_HR['wob-full-text'] = 'Raznovrsni odbori donose bolje odluke. Žene donose poboljšanu suradnju, snažnije upravljanje rizicima i dugoročniji fokus na održivost. Inicijative poput EFC Women on Board Programme ciljaju na 25% zastupljenosti žena do 2027., porast na 35% do 2030.<br><br><strong>Trenutni priručnik: priča o nedovoljnoj zastupljenosti</strong><br>Statistike prikazuju trezven prizor. Kada ključne odluke donosi jedna demografska skupina, sport postaje ranjiv na skupno razmišljanje.<br><br><strong>Promjenjive koristi: izvan kvota raznolikosti</strong><br>Raznovrsniji odbori su jači i donose odluke bolje kvalitete. Odbor koji odražava svoju publiku je vjerodostojniji.<br><br><strong>Strategija napada: ciljane inicijative</strong><br>EFC Women on Board Programme (WOBP), Women in Football (WIF) i globalne inicijative poput Women on Boards Adria (WOBA) grade strukturirani odgovor koji sport treba.<br><br><strong>Završni zvižduk</strong><br>Lijepa igra mora osigurati da njezino vodstvo bude jednako živahno i reprezentativno kao zajednice koje je pokreću.';
TRANSLATIONS_HR['cm-meta'] = 'Mentoria Uvidi &nbsp;·&nbsp; Upravljanje klubom';
TRANSLATIONS_HR['cm-title'] = 'Upravljanje klubom na tržištima u razvoju: lekcije iz Zapadnog Balkana';
TRANSLATIONS_HR['cm-excerpt'] = 'Zapadni Balkan prava je majstorska klasa u vitkom upravljanju klubom — dokazujući da vam nije potreban proračun Premier liga za izgradnju centra izvrsnosti.';
TRANSLATIONS_HR['cm-full-text'] = 'Klubovi u Bosni, Hrvatskoj i Srbiji cvjetaju unatoč ograničenim prihodima od domaće televizije. Naš savjetodavni rad u regiji otkrio je da manji karakter ovih liga nije prepreka — već katalizator za inovaciju i agilno upravljanje.<br><br><strong>1. Akademija kao primarni ekonomski pokretač</strong><br>U Zapadnom Balkanu akademija je poslovni model. Klubovi poput Dinama Zagreb i Partizana Beograd postali su globalne referentne točke za razvoj mladih.<br><br><strong>2. Agilnost u upravljanju</strong><br>Za razliku od birokratskih levijatana Premier liga, balkanski klub može reformirati cijeli odjel u jednoj međusezoni.<br><br><strong>3. Monetiziranje efekta dijaspore</strong><br>Masovna, strastvena dijaspora diljem Njemačke, Austrije i Sjeverne Amerike pruža globalni digitalni doseg.<br><br><strong>4. Navigacija premije volatilnosti</strong><br>Klubovi u Bosni postali su stručnjaci za višestruko financiranje — balans sponzorstva, UEFA uplata i klauzula o transferima.<br><br><strong>5. Infrastruktura: posljednja granica</strong><br>Modernizacija stadiona u Sarajevu ili Beogradu često znači pametnu nadogradnju, a ne gradnju novog stadiona.<br><br><strong>Plan male lige</strong><br>Usredotočujući se na produkciju elitnih igrača i agilno upravljanje, ovi klubovi nadmašuju svoju kategoriju.';
TRANSLATIONS_HR['bre-meta'] = 'Mentoria Uvidi &nbsp;·&nbsp; Investicije';
TRANSLATIONS_HR['bre-title'] = 'Nekretnine i sportska infrastruktura na Balkanu: perspektiva kupovne strane';
TRANSLATIONS_HR['bre-excerpt'] = 'Sportska infrastruktura u Zapadnom Balkanu nedovoljno je kapitalizirana klasa imovine — a za investitore na kupovnoj strani, taj jaz predstavlja privlačnu priliku za dodanu vrijednost.';
TRANSLATIONS_HR['bre-full-text'] = 'Moderna postrojenja u Beogradu, Sarajevu i Splitu više nisu samo o 90 minuta footballa. Ova razvojna zbivanja su ekosustavi nekretnina s komercijalnim sidrima, ugostiteljskim objektima i elitnim centrima za treniranje koji isporučuju 365-dnevni promet.<br><br><strong>Klasa imovine: izvan terena</strong><br>Moderna postrojenja uključuju sportsku medicinu, fitness centre, ugostiteljstvo i MICE te elitne trenažne hubove.<br><br><strong>Okvir due diligence</strong><br>Vlasništvo, usklađenost s propisima, otpornost prihoda i operativni ESG ključni su elementi procjene.<br><br><strong>Zašto Balkan? Prilika nedovoljne ponude</strong><br>Potražnja za visokokvalitetnim sportskim prostorom daleko premašuje ponudu. Zapadni Balkan nudi nižu ulaznu cijenu od Poljske ili Češke, uz sličnu putanju rasta.<br><br><strong>Izvršenje je ključ</strong><br>Balkanska igra kupovne strane nije za pasivnog investitora. Za one koji mogu transformirati propadajući stadion u moderni sportsko-nekretninarski hub, IRR može značajno nadmašiti tradicionalne imovine.';
