TRANSLATIONS_EN['t-people-tag'] = 'The Team';
TRANSLATIONS_EN['sab-bio-short'] = 'Sabrina Buljubašić is a senior sports executive, international sports lawyer and former professional footballer. Her experience spans club leadership, strategic development, governance and high-level football operations, giving Mentoria a rare combination of executive judgement and on-the-ground industry credibility.';
TRANSLATIONS_EN['sab-bio-full'] = 'An accomplished leader recognised for breaking barriers across global football, Sabrina was the first woman appointed CEO of a men\'s football club in Bosnia and Herzegovina. She led FK Sarajevo to a historic era — securing four major trophies, including the club\'s first-ever double title and back-to-back league championships.<br><br>A Leaders 40 Under 40 Award recipient, she founded Dynami Sports Group and became the first person from Bosnia to pass the FIFA Agent Exam. She then led HNK Šibenik to Premier League promotion in her first year at the club. She now serves as General Manager at Hess Sports Group — a London-based investment group growing women\'s sports globally.';
TRANSLATIONS_EN['sab-highlight'] = '"Founder of Dynami Sports Group · International Sports Lawyer · Sports Executive · Former Professional Footballer"';
TRANSLATIONS_EN['sab-badge1'] = '4× Trophy Winner — FK Sarajevo';
TRANSLATIONS_EN['sab-badge3'] = 'FIFA Agent — First from Bosnia';
TRANSLATIONS_EN['sab-badge4'] = 'HNK Šibenik — Premier League Promotion';
TRANSLATIONS_EN['sab-badge5'] = 'Leaders 40 Under 40';
TRANSLATIONS_EN['sab-badge6'] = 'Hess Sports Group — GM';
TRANSLATIONS_EN['jas-bio-short'] = 'Jasmila Hodžić is a sports law specialist and senior football executive with deep experience in legal advisory, governance, regulatory matters and institutional leadership. Her work sits at the intersection of football administration, compliance, stakeholder management and long-term strategic development.';
TRANSLATIONS_EN['jas-bio-full'] = 'She serves as General Secretary and Chief Legal Advisor of FK Sarajevo, where she oversees regulatory compliance, international relations, and key operational processes.<br><br>She holds an LL.M. from Central European University and a Master\'s degree in Sports Marketing and Legal Skills from ISDE Law &amp; Business School, completed in partnership with FC Barcelona. She has further strengthened her executive profile through programs at Harvard Business School, EFC Club Management Programme and the prestigious EFC Women on Board Program.<br><br>Jasmila is actively involved in European football governance through the European Football Clubs, contributing to the Legal and Regulatory Working Group and engaging in the development of key regulatory frameworks shaping modern football. With deep expertise in contract law, dispute resolution, and sports governance, she brings a forward-looking, strategic perspective to football organizations in Southeast Europe and across the international football landscape.';
TRANSLATIONS_EN['jas-highlight'] = '"Sports Law Expert · General Secretary &amp; CLO, FK Sarajevo · ECA Working Group Member · Football Governance Specialist"';
TRANSLATIONS_EN['jas-badge1'] = 'Chief Legal Advisor — FK Sarajevo';
