TRANSLATIONS_EN['jas-badge5'] = 'Harvard Business School';
TRANSLATIONS_EN['jas-badge6'] = 'ECA Legal &amp; Regulatory Working Group';
TRANSLATIONS_EN['t-people-h2'] = 'The People<br>Behind Mentoria';
TRANSLATIONS_EN['t-people-sub'] = 'A leadership team with experience across elite football, legal advisory, governance, investment dialogue and institutional education.';
