TRANSLATIONS_EN['t-articles-tag'] = 'Insights &amp; News';
TRANSLATIONS_EN['ptb-meta'] = 'Mentoria Insights &nbsp;·&nbsp; Education';
TRANSLATIONS_EN['ptb-title'] = 'From Pitch to Boardroom: Preparing Athletes for Life After Sport';
TRANSLATIONS_EN['ptb-excerpt'] = 'Athletes retire young — but their best skills are exactly what boardrooms need. Mentoria bridges the gap between pitch and C-suite.';
TRANSLATIONS_EN['ptb-full-text'] = 'The shift from professional sport to a second career is one of the most demanding transitions a person can make. The qualities that make a champion — resilience, discipline, and strategic thinking — are exactly what modern boardrooms want to recruit.';
TRANSLATIONS_EN['wob-meta'] = 'Mentoria Insights &nbsp;·&nbsp; Governance';
TRANSLATIONS_EN['wob-title'] = 'Tackling the Governance Gap: Why Women on Football Boards Are Essential';
TRANSLATIONS_EN['wob-full-text'] = 'Diverse boards make better decisions. Women bring enhanced collaboration, stronger risk management, and a longer-term focus on sustainability.';
TRANSLATIONS_EN['cm-meta'] = 'Mentoria Insights &nbsp;·&nbsp; Club Management';
TRANSLATIONS_EN['cm-title'] = 'Club Management in Emerging Markets: Lessons from the Western Balkans';
TRANSLATIONS_EN['cm-full-text'] = 'Clubs in Bosnia, Croatia, and Serbia are thriving despite limited domestic TV revenue. Our advisory work in the region has revealed that the smaller nature of these leagues isn\'t a barrier — it is a catalyst for innovation.';
TRANSLATIONS_EN['bre-meta'] = 'Mentoria Insights &nbsp;·&nbsp; Investment';
TRANSLATIONS_EN['bre-title'] = 'Balkans Real Estate &amp; Sports Infrastructure: A Buy-Side Perspective';
TRANSLATIONS_EN['bre-excerpt'] = 'Sports infrastructure in the Western Balkans is an under-capitalised asset class — and for buy-side investors, that gap represents a compelling value-add opportunity.';
TRANSLATIONS_EN['bre-full-text'] = 'Modern facilities in Belgrade, Sarajevo, and Split are no longer just about 90 minutes of football. These developments are community-centric real estate ecosystems with commercial anchors and hospitality venues.';
