TRANSLATIONS_EN['art1-title'] = 'Jasmila Hodžić Moderates Panel on the Future of Football Contracts at Business of Sport';
TRANSLATIONS_EN['art1-excerpt'] = 'Jasmila Hodžić moderated a panel on the future of player contracts and transfer systems at the Business of Sport in Eastern Europe conference in Ljubljana.';
TRANSLATIONS_EN['art1-full-p'] = 'The discussion centred on how a key legal case could influence the direction of professional football, with Hodžić contributing her own insights alongside fellow panelists Frans de Weger, Hrvoje Čabraja, and Pieter Paepe. The event, organised by Blaž Tomažin Bolcar and Sean Cottrell, drew strong audience participation from across the industry.';
TRANSLATIONS_EN['art2-meta'] = 'London &nbsp;·&nbsp; Women\'s Football';
TRANSLATIONS_EN['art2-title'] = 'Sabrina Buljubašić Leads Hess Sports Group\'s Vision for Women\'s Football';
TRANSLATIONS_EN['art2-excerpt'] = 'Sabrina Buljubašić leads Hess Sports Group\'s mission to grow women\'s football globally, anchored by a 75% stake in Waterford FC Women.';
TRANSLATIONS_EN['art2-full-p'] = 'Headquartered in London, Hess Sports Group is a family-owned investment group building a sustainable elite pathway from academy level through to professional football. The model combines joint ownership, affiliate academies, and dual-career development in partnership with South East Technological University (SETU), creating a holistic ecosystem for female athletes that extends from the pitch to the boardroom.';
TRANSLATIONS_EN['art3-meta'] = 'Harvard Business School &nbsp;·&nbsp; Executive Education';
TRANSLATIONS_EN['art3-title'] = 'Jasmila Hodžić Admitted to Executive Leadership Programme at Harvard Business School';
TRANSLATIONS_EN['art3-excerpt'] = 'Jasmila Hodžić has been admitted to the Executive Leadership Programme at Harvard Business School — recognising her expertise in sports law and leadership.';
TRANSLATIONS_EN['art3-full-p'] = 'The programme combines Harvard\'s globally recognised case-based teaching methodology with a curriculum tailored to the strategic, legal, and operational challenges facing senior football executives. Participants engage with real-world scenarios and connect with top industry leaders from clubs and organisations across Europe and beyond. For Hodžić, whose career spans legal advisory, governance, and executive roles within professional football, admission represents both recognition of her expertise and an opportunity to strengthen her leadership capabilities among a select group of professionals shaping the future of the sport.';
