var currentLang = 'en';

// ── Language dropdown ──
document.addEventListener('DOMContentLoaded', function() {
  var toggleBtn = document.getElementById('lang-toggle-btn');
  var menu      = document.getElementById('lang-menu');
  var chevron   = document.getElementById('lang-chevron');
  var btnEn     = document.getElementById('menu-btn-en');
  var btnHr     = document.getElementById('menu-btn-hr');

  if (!toggleBtn || !menu) return;

  function openMenu() {
    menu.style.display = 'block';
    chevron.style.transform = 'rotate(180deg)';
    toggleBtn.style.borderColor = '#F7BC15';
    toggleBtn.style.color = '#F7BC15';
  }
  function closeMenu() {
    menu.style.display = 'none';
    chevron.style.transform = '';
    toggleBtn.style.borderColor = 'rgba(255,255,255,0.35)';
    toggleBtn.style.color = 'rgba(255,255,255,0.9)';
  }

  toggleBtn.addEventListener('click', function(e) {
    e.stopPropagation();
    menu.style.display === 'block' ? closeMenu() : openMenu();
  });

  document.addEventListener('click', function() { closeMenu(); });
  menu.addEventListener('click', function(e) { e.stopPropagation(); });

  toggleBtn.addEventListener('mouseenter', function() { if (menu.style.display !== 'block') { toggleBtn.style.borderColor='#F7BC15'; toggleBtn.style.color='#F7BC15'; } });
  toggleBtn.addEventListener('mouseleave', function() { if (menu.style.display !== 'block') { toggleBtn.style.borderColor='rgba(255,255,255,0.35)'; toggleBtn.style.color='rgba(255,255,255,0.9)'; } });

  btnEn.addEventListener('mouseenter', function() { this.style.background='rgba(247,188,21,0.12)'; });
  btnEn.addEventListener('mouseleave', function() { this.style.background='none'; });
  btnHr.addEventListener('mouseenter', function() { this.style.background='rgba(247,188,21,0.12)'; });
  btnHr.addEventListener('mouseleave', function() { this.style.background='none'; });

  btnEn.addEventListener('click', function() { setLang('en'); closeMenu(); });
  btnHr.addEventListener('click', function() { setLang('hr'); closeMenu(); });
});

function setLang(lang) {
  currentLang = lang;
  var lbl = document.getElementById('lang-btn-label');
  if (lbl) lbl.textContent = lang === 'hr' ? '\uD83C\uDDE7\uD83C\uDDE6 BS' : '\uD83C\uDDEC\uD83C\uDDE7 EN';
  var translations = lang === 'hr' ? TRANSLATIONS_HR : TRANSLATIONS_EN;
  Object.keys(translations).forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.innerHTML = translations[id];
  });
  var tabMap = lang === 'hr'
    ? {'All':'Sve','Sports':'Sport','Investment':'Investicije','Education':'Edukacija'}
    : {'Sve':'All','Sport':'Sports','Investicije':'Investment','Edukacija':'Education'};
  document.querySelectorAll('.tab-btn').forEach(function(btn) {
    var mapped = tabMap[btn.textContent.trim()];
    if (mapped) btn.textContent = mapped;
  });
  // Update expand/collapse button labels
  ['sabrina','jasmila'].forEach(function(name) {
    var btn = document.getElementById(name + '-btn');
    var full = document.getElementById(name + '-full');
    if (!btn || !full) return;
    var isOpen = full.style.display === 'block';
    if (lang === 'hr') {
      btn.textContent = isOpen ? 'Skupi profil ↑' : 'Proširi profil ↓';
    } else {
      btn.textContent = isOpen ? 'Collapse Profile ↑' : 'Expand Profile ↓';
    }
  });
  // Update Read Full Article button labels
  ['lj','hess','hvd','ptb','wob','cm','bre'].forEach(function(aid) {
    var btn = document.getElementById(aid + '-btn');
    var full = document.getElementById(aid + '-full');
    if (!btn || !full) return;
    var isOpen = full.style.display === 'block';
    if (lang === 'hr') {
      btn.textContent = isOpen ? 'Manje' : 'Pročitajte cijeli članak';
    } else {
      btn.textContent = isOpen ? 'Read Less' : 'Read Full Article';
    }
  });
}

function toggleLang() { setLang(currentLang === 'en' ? 'hr' : 'en'); }
